function log(level, ...messages) {
  // 'level' is the first named param
  // 'messages' is a real Array of all remaining args
  const prefix = `[${level.toUpperCase()}]`;
  console.log(prefix, ...messages);
}

log('info', 'Server started');                    // [INFO] Server started
log('warn', 'Memory', 'usage', 'high');           // [WARN] Memory usage high
log('error', 'Crash', 'at', 'line', 42);          // [ERROR] Crash at line 42

// Full array methods available
function sumAll(...nums) {
  return nums.reduce((acc, n) => acc + n, 0);
}
console.log(sumAll(1, 2, 3, 4, 5)); // 15

